#!/usr/bin/env bash
# SessionStart: Asynchronous Wolfram smoke status line appended.
set -eu

PIN="/tmp/wolfram-smoke-banner.txt"
LOG_SM="/tmp/wolfram-smoke.log"

echo "· wolfram pending …" >"${PIN}"

(
  "$HOME/bin/wolfram-mcp-smoke.sh" >"${LOG_SM}" 2>&1
  ec=$?
  case "${ec}" in
    0) printf '%s\n' "· ✓ wolfram 4/4 PASS" >"${PIN}" ;;
    3) printf '%s\n' "· ⚠ wolfram pin drift (exit 3) — see stderr in ${LOG_SM}" >"${PIN}" ;;
    1) printf '%s\n' "· ⚠ wolfram logical FAIL (exit 1)" >"${PIN}" ;;
    *) printf '%s\n' "· ⚠ wolfram smoke exit ${ec}" >"${PIN}" ;;
  esac
) &

read -r SMCELL <"${PIN}" || SMCELL=""
printf '%s\n' "${SMCELL}"
